// Extrai o body do webhook (N8N pode entregar em .body ou na raiz)
const data = $('Webhook').first().json;
const body = data.body || data;
const { message = '', history = [], userId = '' } = body;

// Monta o array de mensagens para a API da OpenAI
// history: últimas 20 mensagens (10 pares) para manter contexto sem estourar tokens
const messages = [
  {
    role: 'system',
    content:
      'Você é um assistente nutricional do Tracker de Macronutrientes. ' +
      'Ajude o usuário com dúvidas sobre alimentação, macronutrientes, ' +
      'calorias e registros diários. Seja direto, objetivo e use dados ' +
      'nutricionais precisos quando souber. ' +
      'Responda sempre em português brasileiro.'
  },
  ...history.slice(-20).map(m => ({
    role: m.role,
    content: String(m.content || '')
  })),
  { role: 'user', content: String(message) }
];

// requestBody pronto para enviar à OpenAI
const requestBody = {
  model: 'gpt-4o-mini',
  messages,
  temperature: 0.7,
  max_tokens: 1000
};

return [{ json: { requestBody, userId } }];
